parameters.jsCode:
const payload = $json;

const dimensions = [
  'Security & Access',
  'Water & Humidity',
  'Utilities & Systems',
  'Building Condition',
  'Outdoor Areas'
];

const propertyHealth = {};
const propertyHealthReasons = {};

for (const dimension of dimensions) {
  const findings = (payload.findings || []).filter(
    f => f.healthDimension === dimension
  );

  const immediateFindings = findings.filter(f => f.severity === 'immediate');
  const monitorFindings = findings.filter(f => f.severity === 'monitor');

  if (immediateFindings.length > 0) {
    propertyHealth[dimension] = 'red';
    propertyHealthReasons[dimension] = `${immediateFindings.length} immediate action finding(s)`;
  } else if (monitorFindings.length > 0) {
    propertyHealth[dimension] = 'yellow';
    propertyHealthReasons[dimension] = `${monitorFindings.length} monitor finding(s)`;
  } else {
    propertyHealth[dimension] = 'green';
    propertyHealthReasons[dimension] = 'No findings reported';
  }
}

return [
  {
    json: {
      receivedAt: new Date().toISOString(),
      schemaVersion: payload.schemaVersion,
      inspection: payload.inspection,
      zones: payload.zones || [],
      findings: payload.findings || [],
      propertyHealth,
      propertyHealthReasons
    }
  }
];

